#version 150

in vec3 Position;
in vec4 Color;
in vec2 UV0;

uniform mat4 ModelViewMat;
uniform mat4 ProjMat;

out vec4 vertexColor;
out vec2 texCoord0;

void main() {
    gl_Position = ProjMat * ModelViewMat * vec4(Position, 1.0);
    vertexColor = Color;
    texCoord0 = UV0;
}

#version 150

uniform sampler2D Sampler0;
uniform float Intensity;

in vec4 vertexColor;
in vec2 texCoord0;

out vec4 fragColor;

void main() {
    vec4 color = texture(Sampler0, texCoord0) * vertexColor;
    // TODO: 应用着色效果
    fragColor = vec4(color.rgb * Intensity, color.a);
}

public class ShaderManager {
    private static ShaderProgram customShader;

    public static void loadShaders() {
        try {
            customShader = new ShaderProgram(
                MinecraftClient.getInstance().getResourceManager(),
                "custom_shader",
                VertexFormats.POSITION_COLOR_TEXTURE
            );
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public static void renderWithShader(Consumer<ShaderProgram> renderFunction) {
        if (customShader != null) {
            customShader.getUniform("Intensity").set(1.5f);
            customShader.use();
            renderFunction.accept(customShader);
            customShader.unuse();
        }
    }
}

void main() {
    vec4 color = texture(Sampler0, texCoord0);
    float outline = 0.0;
    float offset = 1.0 / 256.0;

    for (int x = -1; x <= 1; x++) {
        for (int y = -1; y <= 1; y++) {
            if (x == 0 && y == 0) continue;
            vec4 neighbor = texture(Sampler0, texCoord0 + vec2(x * offset, y * offset));
            outline = max(outline, neighbor.a);
        }
    }

    fragColor = mix(color, vec4(1.0, 0.0, 0.0, 1.0), outline - color.a);
}

void main() {
    vec4 color = vec4(0.0);
    float blurSize = 0.005;

    for (int x = -4; x <= 4; x++) {
        for (int y = -4; y <= 4; y++) {
            color += texture(Sampler0, texCoord0 + vec2(x * blurSize, y * blurSize));
        }
    }

    fragColor = color / 81.0;
}

void main() {
    vec4 color = texture(Sampler0, texCoord0);

    // 灰度化
    float gray = dot(color.rgb, vec3(0.299, 0.587, 0.114));

    // 棕褐色调
    vec3 sepia = vec3(gray * 1.2, gray * 1.0, gray * 0.8);

    fragColor = vec4(mix(color.rgb, sepia, 0.5), color.a);
}
